#!/usr/bin/env python3
import json

questions = [
  {"id":"sh_011","category":"skin_hair","question":"여드름이 생기는 원인은 무엇인가요?","answer":"피지 분비 과다, 모공 내 각질 축적, 여드름균(C. acnes) 번식, 염증 반응이 복합적으로 작용합니다. 호르몬 변화(청소년기, 생리주기), 스트레스, 특정 식품, 화장품도 영향을 줍니다."},
  {"id":"sh_012","category":"skin_hair","question":"자외선 차단제를 매일 발라야 하나요?","answer":"네, 흐린 날에도 UV-A는 구름을 뚫고 피부에 닿습니다. 매일 SPF 30 이상, PA++ 이상의 자외선 차단제를 외출 30분 전 바르고 2~3시간마다 덧바르는 것이 피부 노화와 피부암 예방에 중요합니다."},
  {"id":"sh_013","category":"skin_hair","question":"피부 보습이 중요한 이유는?","answer":"피부 장벽 기능을 유지해 수분 손실을 막고 외부 자극·미생물로부터 보호합니다. 건조한 피부는 가려움증, 피부 장벽 손상, 아토피 피부염 악화로 이어집니다. 세안 후 3분 내 보습이 중요합니다."},
  {"id":"sh_014","category":"skin_hair","question":"아토피 피부염 관리 방법은?","answer":"매일 목욕 후 즉시 저자극 보습제 충분히 바르기, 향이 없는 세제 사용, 면 소재 의류, 집먼지 진드기 제거(침구 세탁), 스테로이드 연고 필요 시 의사 처방대로 적절히 사용합니다."},
  {"id":"sh_015","category":"skin_hair","question":"탈모의 종류에는 어떤 것이 있나요?","answer":"안드로겐성 탈모(유전성, 가장 흔함), 원형 탈모(자가면역), 휴지기 탈모(출산·스트레스·질환 후), 트리코틸로마니아(당김 탈모), 흉터성 탈모(영구적)가 있습니다."},
  {"id":"sh_016","category":"skin_hair","question":"건성 피부와 지성 피부, 혼합성 피부의 차이는?","answer":"건성 피부는 피지 분비가 적고 당기며 잔주름이 이릅니다. 지성 피부는 피지 분비가 많아 번들거리고 여드름이 잘 생깁니다. 혼합성은 T존(이마·코·턱)이 지성이고 볼은 건성입니다."},
  {"id":"sh_017","category":"skin_hair","question":"피부에 빨간 반점이 생기면 무엇을 의심해야 하나요?","answer":"원인이 다양합니다. 알레르기 반응(두드러기), 아토피·습진, 건선, 접촉성 피부염, 장미증(주사), 지루성 피부염 등이 있습니다. 2주 이상 지속되거나 증상이 심하면 피부과 진료를 받으세요."},
  {"id":"sh_018","category":"skin_hair","question":"피부 타입에 맞는 세안 방법은?","answer":"건성 피부는 미온수·순한 클렌저, 하루 1~2회 세안합니다. 지성 피부는 미온수·적합한 클렌저로 하루 2회, 모공 케어에 집중합니다. 모든 피부 타입에서 뜨거운 물 세안은 피지 과다 분비와 건조를 유발합니다."},
  {"id":"sh_019","category":"skin_hair","question":"레티놀이 피부에 어떤 효과가 있나요?","answer":"레티놀(비타민 A 유도체)은 콜라겐 생성 촉진, 세포 회전율 증가, 잔주름 감소, 색소침착 완화에 효과가 있습니다. 처음에는 피부 자극이 있을 수 있어 저농도부터 서서히 사용하고 낮에는 자외선 차단을 꼭 합니다."},
  {"id":"sh_020","category":"skin_hair","question":"비타민 C 세럼이 피부에 도움이 되나요?","answer":"비타민 C(아스코르브산)는 콜라겐 합성 촉진, 미백, 항산화 효과가 있습니다. 불안정한 성분이라 알루미늄 포일·불투명 용기에 보관하고, 황변 시 효능 저하를 의미합니다."},
  {"id":"sh_021","category":"skin_hair","question":"선크림의 물리적·화학적 자외선 차단제 차이는?","answer":"물리적(무기) 차단제(산화아연, 이산화티타늄)는 자외선을 반사합니다. 화학적(유기) 차단제는 자외선을 흡수해 열로 변환합니다. 민감성·아기 피부는 물리적을, 활동적 생활에는 화학적 또는 혼합형을 선호합니다."},
  {"id":"sh_022","category":"skin_hair","question":"탈모 예방을 위한 식이 관리는?","answer":"단백질(달걀, 닭고기, 두부), 철분(붉은 고기, 시금치), 비타민 D, 아연(굴, 견과류), 비오틴(달걀 흰자, 견과류)이 모발 성장에 필요합니다. 극단적 다이어트는 휴지기 탈모를 유발합니다."},
  {"id":"sh_023","category":"skin_hair","question":"두피 건강을 위한 샴푸 방법은?","answer":"두피를 직접 마사지하듯 세정하고 모발은 살살 감습니다. 뜨거운 물은 두피 유분 제거·자극을 주어 미온수가 적합합니다. 린스·트리트먼트는 모발에만 바르고 두피에는 피합니다."},
  {"id":"sh_024","category":"skin_hair","question":"피부 색소침착은 어떻게 관리하나요?","answer":"자외선 차단이 가장 중요합니다. 비타민 C, 나이아신아마이드, 알부틴, 하이드로퀴논(처방) 등 미백 성분이 도움됩니다. 레이저 치료(IPL, Q스위치)나 박피 시술로도 개선 가능합니다."},
  {"id":"sh_025","category":"skin_hair","question":"건선이란 무엇이고 어떻게 치료하나요?","answer":"건선은 면역 이상으로 피부 세포가 과도하게 증식해 비늘 같은 각질과 붉은 반점이 생기는 만성 염증성 피부 질환입니다. 스테로이드 연고, 비타민 D 유도체 연고, 광선 치료, 생물학적 제제로 치료합니다."},
  {"id":"sh_026","category":"skin_hair","question":"모세혈관 확장증(딸기코)은 치료할 수 있나요?","answer":"레이저 치료(PDL, IPL)가 효과적입니다. 장미증 관련이라면 원인 치료(트리거 음식·자외선 회피, 약물)도 병행합니다. 스킨케어는 자극 없는 제품 사용과 철저한 자외선 차단이 중요합니다."},
  {"id":"sh_027","category":"skin_hair","question":"네일(손발톱) 건강을 유지하는 방법은?","answer":"네일을 짧게 유지하고 습기 후 충분히 건조, 과도한 젤 네일·아크릴은 주기적 휴식이 필요합니다. 황변·두꺼워짐·쉽게 부서지는 경우 진균 감염(조갑진균증)을 의심합니다."},
  {"id":"sh_028","category":"skin_hair","question":"피부의 마이크로바이옴이란 무엇인가요?","answer":"피부에 사는 세균, 진균, 바이러스의 집합체입니다. 유익균이 병원균의 성장을 억제하고 면역 훈련에 관여합니다. 과도한 세정, 항생제 남용이 피부 마이크로바이옴을 교란시킵니다."},
  {"id":"sh_029","category":"skin_hair","question":"여드름 흉터를 없애는 방법은?","answer":"레이저 재생술(CO2, 에르비움), 미세침(마이크로니들링), 피부 필링(AHA/BHA), 필러 시술, 미백 성분이 도움됩니다. 여드름을 짜지 않는 것이 흉터 예방의 가장 중요한 방법입니다."},
  {"id":"sh_030","category":"skin_hair","question":"피부 노화를 예방하는 핵심 스킨케어는?","answer":"자외선 차단(가장 중요), 보습, 레티놀(야간 사용), 비타민 C(항산화), 충분한 수면·수분 섭취, 금연, 균형 잡힌 식이가 피부 노화 예방의 핵심입니다."},
  {"id":"sh_031","category":"skin_hair","question":"헤어 드라이어 사용이 모발 손상을 주나요?","answer":"고온 사용은 모발의 수분을 제거하고 단백질 구조를 손상시킵니다. 60~80도 이하의 온도에서 15cm 이상 거리를 두고 사용하고, 열 보호제를 바른 후 사용하면 손상을 줄일 수 있습니다."},
  {"id":"sh_032","category":"skin_hair","question":"피부과 의사가 권하는 기본 스킨케어 루틴은?","answer":"아침: 세안 → 토너 → 세럼(비타민 C 등) → 보습 → 자외선 차단제. 저녁: 클렌징 → 세안 → 토너 → 세럼(레티놀 등) → 보습 크림. 제품 수보다 기본 단계의 충실한 실천이 더 중요합니다."},
  {"id":"sh_033","category":"skin_hair","question":"접촉성 피부염이란 무엇인가요?","answer":"특정 물질 접촉 시 피부 반응이 생기는 상태입니다. 자극성 접촉 피부염(세제, 화학물질 직접 자극)과 알레르기성 접촉 피부염(니켈, 향료 등 면역 반응)으로 구분합니다."},
  {"id":"sh_034","category":"skin_hair","question":"피부에 나타나는 당뇨 증상은?","answer":"건조하고 가려운 피부, 상처 회복 지연, 재발성 피부 감염, 흑색극세포증(목·겨드랑이의 거무스름한 두꺼운 피부), 당뇨병성 수포, 발의 무감각·궤양이 당뇨와 관련된 피부 증상입니다."},
  {"id":"sh_035","category":"skin_hair","question":"발모증(원형 탈모)이 생겼을 때 치료 방법은?","answer":"스테로이드 국소 주사(가장 흔함), 스테로이드 연고, 미녹시딜, JAK 억제제(심한 경우)가 사용됩니다. 대부분 수개월~1년 내 자연 회복되지만 재발이 흔합니다. 스트레스 관리도 중요합니다."},
  {"id":"sh_036","category":"skin_hair","question":"두피 비듬의 원인과 관리는?","answer":"비듬은 말라세지아(Malassezia) 효모균 과증식, 지루성 피부염, 건성 두피에 의해 생깁니다. 항진균 성분(케토코나졸, 피리치온 아연) 샴푸가 효과적입니다. 심한 경우 피부과 치료가 필요합니다."},
  {"id":"sh_037","category":"skin_hair","question":"피부 습진과 건선은 어떻게 다른가요?","answer":"습진(아토피 피부염)은 주로 어린이에서 시작하며 가려움이 주 증상이고, 양쪽 팔꿈치 안쪽·무릎 뒤쪽·얼굴에 잘 생깁니다. 건선은 성인에서 흔하며 팔꿈치 바깥·무릎·두피에 두꺼운 흰 비늘이 나타납니다."},
  {"id":"sh_038","category":"skin_hair","question":"피부과에서 사용하는 화학 박피(필링)란?","answer":"AHA(글리콜릭산), BHA(살리실산), TCA, 페놀 등 산성 용액으로 표피~진피를 손상시켜 새 피부 재생을 유도합니다. 잡티, 여드름 흉터, 잔주름, 색소 불균일 개선에 사용됩니다."},
  {"id":"sh_039","category":"skin_hair","question":"자외선에 의한 피부 손상을 어떻게 예방하나요?","answer":"SPF 30이상 PA+++ 자외선 차단제 매일 사용, 오전 10시~오후 4시 야외 활동 자제, 긴소매·모자·선글라스 착용, 그늘 이용, 하루 2~3회 차단제 재도포가 피부암과 광노화 예방에 필수입니다."},
  {"id":"sh_040","category":"skin_hair","question":"헤어 케어에서 단백질 트리트먼트란?","answer":"손상된 모발의 케라틴 구조를 보충하는 트리트먼트입니다. 화학적 시술(염색, 펌) 후 모발 강화에 도움됩니다. 그러나 건강한 모발에 과도한 단백질 처치는 단단해지고 끊어지기 쉬운 문제가 생길 수 있습니다."},
  {"id":"sh_041","category":"skin_hair","question":"나이아신아마이드가 피부에 어떤 효과가 있나요?","answer":"나이아신아마이드(비타민 B3)는 모공 축소, 피부 장벽 강화, 색소침착 감소, 피지 조절, 항염증 효과가 있습니다. 대부분의 피부 타입에 잘 맞고 다른 성분과 조합하기 쉬워 인기 있는 성분입니다."},
  {"id":"sh_042","category":"skin_hair","question":"남성형 탈모(안드로겐성 탈모) 치료는?","answer":"미녹시딜(국소 도포, 모발 성장 촉진), 피나스테라이드(경구, DHT 억제), 두타스테라이드(경구), 모발이식 수술이 주요 치료법입니다. 조기 치료 시작이 더 효과적입니다."},
  {"id":"sh_043","category":"skin_hair","question":"피부 결절과 낭종의 차이는?","answer":"결절은 진피나 피하 조직의 고형 종양입니다. 낭종(피지낭종 등)은 분비물이 차있는 주머니입니다. 양성이 대부분이지만 빠르게 자라거나 모양이 변하는 경우 피부과 진료가 필요합니다."},
  {"id":"sh_044","category":"skin_hair","question":"손발 무좀을 치료하는 방법은?","answer":"무좀은 진균 감염으로 항진균 크림(클로트리마졸, 테르비나핀)을 4~6주 이상 꾸준히 발라야 합니다. 발을 건조하게 유지하고, 공중 화장실에서 맨발을 피하고, 항진균 발 파우더도 도움됩니다."},
  {"id":"sh_045","category":"skin_hair","question":"여성형 탈모와 남성형 탈모의 차이는?","answer":"남성형 탈모는 이마가 넓어지고 정수리가 비는 M자·O자 패턴입니다. 여성형 탈모는 가르마가 넓어지는 전반적 정수리 탈모 패턴을 보이며 완전한 탈모로 진행하는 경우는 드뭅니다."},
  {"id":"sh_046","category":"skin_hair","question":"피부암의 종류와 위험 신호는?","answer":"기저세포암(가장 흔함), 편평세포암, 흑색종(가장 위험)이 주요 피부암입니다. ABCDE 법칙(비대칭·불규칙경계·색다양·6mm이상·변화)에 해당하는 점이나 병변은 즉시 피부과 진료를 받으세요."},
  {"id":"sh_047","category":"skin_hair","question":"탈모에 두피 마사지가 효과적인가요?","answer":"연구에서 규칙적인 두피 마사지(하루 4분)가 두피 혈류를 개선하고 모발 성장을 자극할 수 있음을 보여줍니다. 미녹시딜과 병용 시 효과가 더 좋습니다. 너무 강하게 마사지하면 탈모를 악화시킬 수 있습니다."},
  {"id":"sh_048","category":"skin_hair","question":"피부과에서 히알루론산 필러는 어떻게 사용되나요?","answer":"히알루론산 필러는 수분을 흡수해 피부를 채우는 주사 시술입니다. 볼 꺼짐, 팔자 주름, 입술 확대에 사용되며 효과는 6~18개월 지속됩니다. 히알루로니다제 효소로 용해가 가능합니다."},
  {"id":"sh_049","category":"skin_hair","question":"피부 모공을 줄이는 방법은?","answer":"모공은 실제로 축소되지 않지만 청결 유지(BHA 세정), 레티놀 사용(피지 조절), 나이아신아마이드, 레이저·IPL 시술로 모공을 더 작아 보이게 할 수 있습니다. 선크림으로 모공 주변 피부 처짐을 예방합니다."},
  {"id":"sh_050","category":"skin_hair","question":"두피에 지루성 피부염이 생기면?","answer":"지루성 피부염은 기름기 있는 황색 비늘과 붉음증이 특징입니다. 케토코나졸·셀렌화황·아연 피리치온 함유 샴푸를 주 2~3회 사용합니다. 두피 보습과 스트레스 관리도 재발 예방에 도움됩니다."},
  {"id":"sh_051","category":"skin_hair","question":"피부 타입이 변할 수 있나요?","answer":"네, 나이, 계절, 호르몬 변화, 생활환경, 스킨케어 루틴 변화에 따라 피부 타입이 변할 수 있습니다. 청소년기 지성 피부가 30~40대에 건성으로 변하는 경우가 흔합니다."},
  {"id":"sh_052","category":"skin_hair","question":"보톡스가 피부에 어떻게 작용하나요?","answer":"보툴리눔 독소(보톡스)는 신경-근육 접합부에서 아세틸콜린 분비를 차단해 근육 수축을 일시적으로 억제합니다. 이마·미간·눈가 주름, 사각턱 축소, 다한증 치료에 사용됩니다. 효과는 4~6개월입니다."},
  {"id":"sh_053","category":"skin_hair","question":"두드러기가 자주 생기면 어떻게 해야 하나요?","answer":"급성 두드러기(6주 미만)는 음식·약·감염이 원인인 경우가 많습니다. 만성 두드러기는 원인 불명이 많고 항히스타민제로 증상을 조절합니다. 호흡 곤란·혀 부종이 동반되면 즉시 응급 처치가 필요합니다."},
  {"id":"sh_054","category":"skin_hair","question":"셀프 케어로 할 수 있는 발 각질 관리는?","answer":"발을 20분 미온수에 불리고 각질 제거기로 부드럽게 제거 후, 발 크림을 충분히 바르고 양말을 신어 보습합니다. 주 1~2회가 적절하며, 과도한 제거는 피부 장벽을 손상시킵니다."},
  {"id":"sh_055","category":"skin_hair","question":"면도 후 피부 트러블을 예방하는 방법은?","answer":"세안 후 면도 크림·폼으로 연화, 결 방향으로 면도, 예리한 면도기 사용, 면도 후 알코올 없는 진정 토너나 보습제를 즉시 바릅니다. 면도 열상은 면도 방향을 바꿔 개선합니다."},
  {"id":"sh_056","category":"skin_hair","question":"피부에 좋은 음식은 무엇인가요?","answer":"토마토(라이코펜·자외선 보호), 블루베리(항산화), 연어(오메가-3·보습), 아보카도(비타민 E·건강지방), 견과류(셀레늄·비타민 E), 녹차(카테킨), 당근(베타카로텐)이 피부 건강에 좋습니다."},
  {"id":"sh_057","category":"skin_hair","question":"임신 중 피부에 어떤 변화가 생기나요?","answer":"피부 과다색소침착(기미·흑갈색 선), 임신선(스트레치 마크), 여드름 악화 또는 개선, 정맥 돌출이 흔합니다. 기미는 출산 후 일부 옅어질 수 있으며 철저한 자외선 차단이 중요합니다."},
  {"id":"sh_058","category":"skin_hair","question":"손 건강 관리는 어떻게 하나요?","answer":"자주 씻은 후 핸드 크림 즉시 바르기, 고무장갑 착용으로 세제 접촉 최소화, 핸드 크림 자기 전 두껍게 바르고 면 장갑 착용하기, 손 큐티클 과도 정리 자제가 손 피부 건강에 중요합니다."},
  {"id":"sh_059","category":"skin_hair","question":"두피 열감이나 가려움증은 왜 생기나요?","answer":"두피 지루성 피부염, 건선, 비듬, 모낭염, 알레르기성 접촉 피부염(헤어 제품), 과도한 두피 피지 등이 원인입니다. 향이 없는 순한 제품 사용과 두피 청결 유지가 1차 관리법입니다."},
  {"id":"sh_060","category":"skin_hair","question":"피부 광노화(photoaging)란 무엇인가요?","answer":"자외선에 의한 만성 피부 손상으로 주름, 색소반점, 피부 처짐, 모세혈관 확장이 생깁니다. 내인성 노화(자연적)보다 광노화가 피부 외관 변화의 80%를 차지합니다. 자외선 차단이 최선의 예방입니다."},
  {"id":"sh_061","category":"skin_hair","question":"피부 세럼과 크림의 차이는?","answer":"세럼은 분자가 작고 고농도 활성 성분이 피부 깊숙이 침투합니다. 크림·로션은 보습 장벽을 형성합니다. 올바른 순서는 세안→토너→세럼(얇은 것→두꺼운 것 순)→크림입니다."},
  {"id":"sh_062","category":"skin_hair","question":"모낭염이란 무엇이며 어떻게 치료하나요?","answer":"모낭에 세균(주로 황색포도상구균) 또는 진균이 감염되어 붉은 반점과 고름이 생깁니다. 경미한 경우 항균 비누, 온찜질로 관리합니다. 심한 경우 항생제 연고나 경구 항생제가 필요합니다."},
  {"id":"sh_063","category":"skin_hair","question":"피부에 갑자기 점이 많이 생기면 걱정해야 하나요?","answer":"대부분의 새 점은 양성이지만, 급격히 변하거나 커지는 점, ABCDE 기준에 해당하는 점은 악성 흑색종을 배제하기 위해 피부과 진료가 필요합니다. 정기적인 전신 피부 검진을 권장합니다."},
  {"id":"sh_064","category":"skin_hair","question":"수면이 피부에 미치는 영향은?","answer":"수면 중 성장호르몬이 분비되어 피부 세포 재생과 콜라겐 합성이 활성화됩니다. 수면 부족은 피부 장벽 손상, 수분 손실 증가, 피부 칙칙함, 다크서클, 피부 염증 증가로 이어집니다."},
  {"id":"sh_065","category":"skin_hair","question":"피부 주름을 예방하는 습관은?","answer":"자외선 차단(가장 중요), 충분한 수면(7~9시간), 금연, 충분한 수분 섭취, 균형 잡힌 영양(항산화 풍부), 보습, 레티놀·비타민 C 사용, 스트레스 관리가 피부 주름 예방에 핵심입니다."},
  {"id":"sh_066","category":"skin_hair","question":"AHA와 BHA 각질 제거제의 차이는?","answer":"AHA(글리콜릭산, 락틱산)는 수용성으로 피부 표면 각질을 제거해 칙칙한 피부·잔주름에 효과적입니다. BHA(살리실산)는 지용성으로 모공 속까지 침투해 여드름·블랙헤드에 더 효과적입니다."},
  {"id":"sh_067","category":"skin_hair","question":"탈모 환자에게 모발이식 수술이 적합한가요?","answer":"안드로겐성 탈모로 공여부(뒷머리) 모발이 충분한 경우 적합합니다. FUT(줄기법)와 FUE(단위 채취)가 있으며, 이식 후 3~6개월 내 탈락 후 재성장합니다. 최종 결과는 12~18개월 후 확인합니다."},
  {"id":"sh_068","category":"skin_hair","question":"피부 알레르기 검사는 어떻게 하나요?","answer":"패치 테스트는 알레르기성 접촉 피부염 원인 물질 파악에 사용합니다. 피부 단자 검사(Prick test)는 IgE 매개 즉각형 알레르기(음식, 흡입 알레르기) 확인에 적합합니다."},
  {"id":"sh_069","category":"skin_hair","question":"임신선(스트레치 마크)이 생기면 없어지나요?","answer":"완전히 없어지지는 않지만 시간이 지나면서 붉거나 보라색에서 은백색으로 옅어집니다. 보습 크림, 레티노이드(임신·수유 중 금기), 레이저·마이크로니들링 시술이 개선에 도움됩니다."},
  {"id":"sh_070","category":"skin_hair","question":"콜라겐이 피부에서 어떤 역할을 하나요?","answer":"콜라겐은 피부의 탄력과 구조를 유지하는 주요 단백질입니다. 20대부터 매년 1%씩 감소합니다. 자외선·흡연이 콜라겐 분해를 촉진합니다. 레티놀, 비타민 C, 마이크로니들링이 콜라겐 생성을 자극합니다."},
  {"id":"sh_071","category":"skin_hair","question":"두피 탈모 치료에 PRP(혈소판 풍부 혈장) 주사가 효과적인가요?","answer":"PRP는 자신의 혈액에서 성장인자를 농축해 두피에 주사합니다. 일부 연구에서 모발 밀도 증가와 탈모 감소 효과를 보고합니다. 단독 또는 미녹시딜과 병용 시 효과적입니다. 3~6회 시술이 일반적입니다."},
  {"id":"sh_072","category":"skin_hair","question":"피부에 튼살이 생기는 이유는?","answer":"급격한 체중 증가·감소, 임신, 급성장기에 피부 진피층의 콜라겐·엘라스틴 섬유가 늘어남을 따라가지 못해 찢어집니다. 허벅지, 복부, 가슴, 등에 자주 생깁니다."},
  {"id":"sh_073","category":"skin_hair","question":"영양 부족이 모발에 미치는 영향은?","answer":"단백질 결핍은 모발 성장 둔화·가늘어짐을 일으킵니다. 철분 결핍은 휴지기 탈모의 흔한 원인입니다. 비타민 D, 아연, 비오틴 결핍도 탈모를 유발합니다. 균형 잡힌 영양이 모발 건강의 기본입니다."},
  {"id":"sh_074","category":"skin_hair","question":"피부 건강을 위해 물을 많이 마셔야 하나요?","answer":"적절한 수분 섭취는 피부 탄력 유지에 도움됩니다. 그러나 정상 수분을 넘어 과도하게 마신다고 피부가 더 좋아지지는 않습니다. 수분은 적절한 보습 크림과 함께 사용해야 피부 내 유지됩니다."},
  {"id":"sh_075","category":"skin_hair","question":"손톱이 변색되는 원인은?","answer":"노란빛: 진균 감염·니코틴. 흰빛: 알부민 저하·신부전. 검정빛: 외상·흑색종. 파란빛: 산소 저하. 스파누클(반달 모양) 변화: 갑상선·빈혈. 손발톱 변색은 전신 질환 신호일 수 있습니다."},
  {"id":"sh_076","category":"skin_hair","question":"피부과에서 IPL(강한 펄스 빛) 시술이란?","answer":"여러 파장의 빛으로 색소반점, 모세혈관, 여드름균, 잔주름을 동시에 개선합니다. 시술 후 일시적으로 색소가 더 진해졌다가 떨어집니다. 자외선 차단이 치료 효과 유지에 필수입니다."},
  {"id":"sh_077","category":"skin_hair","question":"피부에 흉터가 생기면 어떻게 관리하나요?","answer":"상처 치유 초기에는 실리콘 겔·시트를 6~12개월 사용합니다. 자외선 차단, 화상이나 수술 흉터에는 레이저(PDL, 프락셀), 코르티코스테로이드 주사, 피부 교정 시술이 효과적입니다."},
  {"id":"sh_078","category":"skin_hair","question":"피부 간지러움이 지속되면 어떻게 해야 하나요?","answer":"만성 소양증은 피부 질환(건선, 아토피), 전신 질환(신부전, 간질환, 갑상선 이상, 림프종), 신경학적 원인이 있을 수 있습니다. 2주 이상 지속되거나 발진 없이 전신 가려움이 있으면 의사 진료가 필요합니다."},
  {"id":"sh_079","category":"skin_hair","question":"비타민 E가 피부에 어떻게 도움이 되나요?","answer":"비타민 E는 항산화 효과로 자유 라디칼로부터 피부 세포를 보호합니다. 보습 효과도 있어 건성 피부에 좋습니다. 그러나 일부에서 접촉 피부염이 생길 수 있어 패치 테스트 후 사용을 권장합니다."},
  {"id":"sh_080","category":"skin_hair","question":"피부 장벽(skin barrier)을 강화하는 방법은?","answer":"세라마이드, 히알루론산, 지방산이 포함된 보습제 사용, 과도한 세정 자제, 향 없는 제품 선택, 충분한 수면, 스트레스 관리, 자외선 차단이 피부 장벽 강화에 도움됩니다."},
  {"id":"sh_081","category":"skin_hair","question":"피부과에서 하는 프락셀 레이저란?","answer":"프락셀(분획 레이저)은 피부에 수천 개의 미세 열 손상 기둥을 만들어 콜라겐 재생을 유도합니다. 여드름 흉터, 노화 주름, 색소 불균일에 효과적입니다. 회복 기간이 레이저 종류에 따라 다릅니다."},
  {"id":"sh_082","category":"skin_hair","question":"면 마스크와 시트 마스크의 차이는?","answer":"시트 마스크는 단시간(15~20분) 집중 수분·영양 공급에 적합하나 지속 효과는 짧습니다. 수면 마스크(워시오프 팩)는 밤새 수분 장벽을 형성합니다. 피부 상태에 따라 선택하고 보습제로 마무리가 중요합니다."},
  {"id":"sh_083","category":"skin_hair","question":"음식과 피부 트러블의 관계는?","answer":"유제품, 고혈당지수 식품(흰쌀, 흰빵, 설탕)이 여드름을 악화시킨다는 연구가 있습니다. 개인차가 크기 때문에 음식 일지로 자신의 유발 음식을 파악하는 것이 도움됩니다."},
  {"id":"sh_084","category":"skin_hair","question":"두피 스케일링이란 무엇인가요?","answer":"두피의 묵은 각질과 피지를 제거하는 관리입니다. 두피 전용 스케일러(살리실산, AHA)나 스크럽을 사용합니다. 두피 비듬·기름기·모공 막힘 개선에 도움되며 주 1~2회가 적절합니다."},
  {"id":"sh_085","category":"skin_hair","question":"피부 노화와 호르몬의 관계는?","answer":"여성은 폐경 후 에스트로겐 감소로 콜라겐 합성이 줄어 피부가 얇아지고 건조해집니다. 남성은 테스토스테론 감소로 피부 탄력이 서서히 줄어듭니다. 호르몬 보충 요법이 피부 개선에 도움될 수 있으나 의사 상담이 필요합니다."},
  {"id":"sh_086","category":"skin_hair","question":"샴푸 교체가 탈모를 일으킬 수 있나요?","answer":"샴푸 교체만으로 탈모가 생기지는 않습니다. 그러나 성분에 알레르기가 있거나 두피 자극이 심한 제품이라면 두피 건강에 영향을 줄 수 있습니다. 탈모가 지속되면 피부과 진료를 받으세요."},
  {"id":"sh_087","category":"skin_hair","question":"피부과 치료 중 항생제 연고와 스테로이드 연고를 함께 써도 되나요?","answer":"의사 처방에 따라 병용이 가능하며 각각의 역할이 다릅니다. 항생제 연고는 세균 감염, 스테로이드는 염증 완화에 사용합니다. 스테로이드 연고는 처방 기간 이상 임의로 사용하면 피부 위축 등 부작용이 생길 수 있습니다."},
  {"id":"sh_088","category":"skin_hair","question":"모발 이식 후 관리 방법은?","answer":"이식 후 72시간은 모발이식 부위에 물이 닿지 않도록 합니다. 처음 2주는 직사광선, 격한 운동, 수영을 피합니다. 3~4개월간 이식 모발이 빠졌다가 6개월~1년 사이 최종 결과가 나타납니다."},
  {"id":"sh_089","category":"skin_hair","question":"얼굴 홍조(붉어짐)가 지속되면 어떻게 해야 하나요?","answer":"일시적 홍조는 더위·스트레스·알코올이 원인입니다. 지속적 홍조는 장미증(로사시아)을 의심해야 합니다. 자외선 차단, 유발 인자 회피, 항생제 크림(메트로니다졸) 또는 처방 약물로 치료합니다."},
  {"id":"sh_090","category":"skin_hair","question":"피부 건강을 위해 금연이 중요한 이유는?","answer":"흡연은 피부 혈류를 감소시키고 활성 산소를 증가시켜 피부 노화를 20~30년 앞당깁니다. 콜라겐 분해 효소를 활성화하고 비타민 C를 고갈시킵니다. 금연 후 피부 혈류가 회복되어 안색이 개선됩니다."},
  {"id":"sh_091","category":"skin_hair","question":"피부에 기미가 생기는 이유와 관리는?","answer":"자외선, 임신·피임약(호르몬), 유전이 기미의 주요 원인입니다. 자외선 차단(SPF50+), 비타민 C·나이아신아마이드 국소 도포, 하이드로퀴논(처방), 레이저 치료가 효과적입니다."},
  {"id":"sh_092","category":"skin_hair","question":"피부 세안 횟수는 어떻게 해야 하나요?","answer":"일반적으로 하루 2회(아침·저녁) 세안이 적절합니다. 건성이나 민감성 피부는 아침에 물 세안만 해도 충분할 수 있습니다. 과도한 세안은 피부 장벽 손상과 피지 과다 분비를 유발합니다."},
  {"id":"sh_093","category":"skin_hair","question":"피부과에서 사용하는 마이크로니들링이란?","answer":"수백 개의 미세 침이 피부에 작은 구멍을 만들어 콜라겐 생성을 자극합니다. 흉터, 주름, 모공 개선에 사용됩니다. 시술 후 48시간 이상 자외선 차단과 자극성 제품 사용을 피해야 합니다."},
  {"id":"sh_094","category":"skin_hair","question":"피부과 진료가 필요한 상황은 어떤 것인가요?","answer":"2주 이상 지속되는 발진·가려움, 빠르게 변하는 점이나 병변, 상처가 낫지 않는 경우, 전신 가려움(발진 없음), 급격한 탈모, 원인 불명의 색소 변화, 자가 치료에 반응 없는 여드름·습진 시 피부과 진료가 필요합니다."},
  {"id":"sh_095","category":"skin_hair","question":"파운데이션이 피부 트러블을 일으키나요?","answer":"코메도제닉(모공 막힘 유발) 성분이 있는 메이크업은 여드름을 악화시킬 수 있습니다. '논코메도제닉(Non-comedogenic)' 표기 제품을 선택하고, 충분한 더블 클렌징으로 메이크업을 잘 제거하는 것이 중요합니다."},
  {"id":"sh_096","category":"skin_hair","question":"피부 건강에서 수분 섭취와 외부 보습의 차이는?","answer":"수분 섭취는 내부에서 피부 기능을 지원하지만, 직접적인 피부 수분 공급 효과는 국소 보습제만 못합니다. 가장 효과적인 전략은 내부 수분 섭취(하루 1.5~2L)와 외부 보습(히알루론산·세라마이드)을 모두 실천하는 것입니다."},
  {"id":"sh_097","category":"skin_hair","question":"탈모 치료제 미녹시딜의 부작용은?","answer":"가장 흔한 부작용은 두피 자극·가려움·비듬, 초기 6~8주간 일시적 탈락 증가입니다. 경구 미녹시딜은 체모 증가, 저혈압, 두통이 생길 수 있습니다. 여성이 남성용 농도를 사용하면 체모가 증가할 수 있습니다."},
  {"id":"sh_098","category":"skin_hair","question":"피부 건강을 위한 수면 자세는?","answer":"옆으로 자는 경우 배게에 얼굴이 닿아 '수면 주름'이 생길 수 있습니다. 실크 베개 커버, 등을 대고 자는 자세가 수면 주름 예방에 좋습니다. 취침 전 보습 크림을 충분히 바르는 것도 피부 수분 유지에 도움됩니다."},
  {"id":"sh_099","category":"skin_hair","question":"두피 모낭에서 모발이 만들어지는 과정은?","answer":"모낭의 기질 세포가 분열해 모발 케라틴을 생성합니다. 성장기(Anagen, 2~7년)→퇴행기(Catagen, 2~3주)→휴지기(Telogen, 3개월)→탈락 주기를 반복합니다. 하루 50~100개 탈모는 정상입니다."},
  {"id":"sh_100","category":"skin_hair","question":"피부 건강의 핵심 요약은 무엇인가요?","answer":"자외선 차단(매일 SPF30+), 일일 세안과 보습, 균형 잡힌 식이(항산화·오메가3), 충분한 수면, 금연, 수분 섭취, 스트레스 관리, 규칙적인 피부과 검진이 건강하고 아름다운 피부 유지의 핵심입니다."}
]

